// frontend/src/components/ResultView.js
import React from "react";
import Quiz from "./Quiz";

export default function ResultView({data}) {
  if (!data) return null;

  const { text, quiz } = data;

  return (
    <div style={{marginTop:"25px"}}>
      
      <div style={{
        padding:"20px",
        background:"#f8faff",
        borderRadius:"10px",
        border:"1px solid #dbe3ff",
        marginBottom:"20px"
      }}>
        <h2 style={{color:"#2563eb", marginBottom:"10px"}}>Extracted Text</h2>
        <pre style={{
          whiteSpace:"pre-wrap",
          background:"white",
          padding:"15px",
          borderRadius:"8px",
          border:"1px solid #ddd"
        }}>
          {text}
        </pre>
      </div>

      <div style={{
        padding:"20px",
        background:"#f0f6ff",
        borderRadius:"10px",
        border:"1px solid #c9d9ff"
      }}>
        <h3 style={{color:"#2563eb"}}>Generated Quiz</h3>
        <Quiz items={quiz || []} />
      </div>

    </div>
  );
}
